selector_to_html = {"a[href=\"barcode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Symbologies<a class=\"headerlink\" href=\"#symbologies\" title=\"Lien vers cette rubrique\">#</a></h1><h2>D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"faq.html#question-3-the-scanner-scans-successfully-beeps-three-times-and-fails-to-upload-data-how-can-i-solve-this-problem\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Question 3:Le scanner scanne avec succ\u00e8s, bip trois fois et ne t\u00e9l\u00e9charge pas de donn\u00e9es. Comment puis-je r\u00e9soudre ce probl\u00e8me ?<a class=\"headerlink\" href=\"#question-3-the-scanner-scans-successfully-beeps-three-times-and-fails-to-upload-data-how-can-i-solve-this-problem\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong></p>", "a[href=\"wired.html#automatic-selection-of-wired-wireless-transmission\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">S\u00e9lection automatique de la transmission filaire/sans fil<a class=\"headerlink\" href=\"#automatic-selection-of-wired-wireless-transmission\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"keyboard.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Param\u00e8tres du clavier<a class=\"headerlink\" href=\"#keyboard-settings\" title=\"Lien vers cette rubrique\">#</a></h1><h2>R\u00e9glages du cas<a class=\"headerlink\" href=\"#case-settings\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Normale<a class=\"headerlink\" href=\"#normal\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"scanmode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"scanmode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Fin de la configuration<a class=\"headerlink\" href=\"#end-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wired.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode filaire<a class=\"headerlink\" href=\"#wired-mode\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Mode de transmission<a class=\"headerlink\" href=\"#transmission-mode\" title=\"Lien vers cette rubrique\">#</a></h2><h3>C\u00e2ble USB comme Clavier<a class=\"headerlink\" href=\"#usb-cable-as-keyboard\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"system.html#battery-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Informations sur la batterie<a class=\"headerlink\" href=\"#battery-information\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"faq.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">FAQ<a class=\"headerlink\" href=\"#faq\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Question 1 : Le scan est r\u00e9ussi, le buzzer sonne une fois, mais aucune donn\u00e9e n\u2019est t\u00e9l\u00e9charg\u00e9e ?<a class=\"headerlink\" href=\"#question-1-the-scan-is-successful-the-buzzer-sounds-once-but-no-data-is-uploaded\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong> Le scanner est entr\u00e9 en mode stockage et doit scanner <a class=\"reference internal\" href=\"working.html#normal-mode\"><span class=\"std std-ref\">Mode Normal</span></a> pour r\u00e9cup\u00e9rer.</p>", "a[href=\"working.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de travail<a class=\"headerlink\" href=\"#working-mode\" title=\"Lien vers cette rubrique\">#</a></h1><p>Dans la zone de travail en dehors de la port\u00e9e de la 2. R\u00e9cepteur G ou signal Bluetooth, vous pouvez activer le mode de stockage du scanner en suivant les \u00e9tapes d\u00e9crites ci-dessous. Dans ce mode, toutes les donn\u00e9es num\u00e9ris\u00e9es seront stock\u00e9es directement dans le scanner. Avant de t\u00e9l\u00e9charger les donn\u00e9es, il sera sauvegard\u00e9 en permanence dans le scanner afin que vous puissiez t\u00e9l\u00e9charger les donn\u00e9es lorsque le scanner est dans la plage de signal de r\u00e9ception.</p>", "a[href=\"process.html#prefix\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Pr\u00e9fixe<a class=\"headerlink\" href=\"#prefix\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Ajouter un pr\u00e9fixe<a class=\"headerlink\" href=\"#add-prefix\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"faq.html#question-5-scan-successful-uploaded-data-incorrect\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Question 5:Scan r\u00e9ussi, donn\u00e9es t\u00e9l\u00e9charg\u00e9es incorrectes ?<a class=\"headerlink\" href=\"#question-5-scan-successful-uploaded-data-incorrect\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong></p>", "a[href=\"process.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u00c9dition de donn\u00e9es<a class=\"headerlink\" href=\"#data-editing\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Format de sortie<a class=\"headerlink\" href=\"#output-format\" title=\"Lien vers cette rubrique\">#</a></h2><p>Pour modifier le Format de Transmission de Donn\u00e9es de Scannage, scannez l\u2019un des huit codes \u00e0 barres correspondant au format souhait\u00e9.</p>", "a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">R\u00e9glages du volume<a class=\"headerlink\" href=\"#volume-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Scannez le code de r\u00e9glage correspondant pour activer/d\u00e9sactiver l\u2019invite sonore du scanner</p>", "a[href=\"process.html#suffix\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Suffix<a class=\"headerlink\" href=\"#suffix\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Ajouter un suffixe<a class=\"headerlink\" href=\"#add-suffix\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"barcode.html#only-enable-1d-symbologies\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Activer uniquement les symboles 1D<a class=\"headerlink\" href=\"#only-enable-1d-symbologies\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#medium-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Vitesse moyenne<a class=\"headerlink\" href=\"#medium-speed\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"scanmode.html#continuous-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode continu<a class=\"headerlink\" href=\"#continuous-mode\" title=\"Lien vers cette rubrique\">#</a></h2><p>Le scanner fonctionne en continu. Si le scan est r\u00e9ussi ou si le temps de scan d\u00e9passe le temps de travail unique, le scan actuel se termine. Si le temps d\u00e9passe le temps sp\u00e9cifi\u00e9, la prochaine analyse est automatiquement d\u00e9clench\u00e9e.</p>", "a[href=\"faq.html#question-4-the-scanner-beeps-five-times-when-a-button-is-pressed-how-can-i-solve-this-problem\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Question 4 : Le scanner \u00e9met cinq bips lorsqu\u2019un bouton est press\u00e9, comment puis-je r\u00e9soudre ce probl\u00e8me?<a class=\"headerlink\" href=\"#question-4-the-scanner-beeps-five-times-when-a-button-is-pressed-how-can-i-solve-this-problem\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong> La batterie est faible et doit \u00eatre recharg\u00e9e avant de pouvoir \u00eatre r\u00e9utilis\u00e9e.</p>", "a[href=\"character.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Fin de la configuration<a class=\"headerlink\" href=\"#end-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"character.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"faq.html#question-1-the-scan-is-successful-the-buzzer-sounds-once-but-no-data-is-uploaded\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Question 1 : Le scan est r\u00e9ussi, le buzzer sonne une fois, mais aucune donn\u00e9e n\u2019est t\u00e9l\u00e9charg\u00e9e ?<a class=\"headerlink\" href=\"#question-1-the-scan-is-successful-the-buzzer-sounds-once-but-no-data-is-uploaded\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong> Le scanner est entr\u00e9 en mode stockage et doit scanner <a class=\"reference internal\" href=\"working.html#normal-mode\"><span class=\"std std-ref\">Mode Normal</span></a> pour r\u00e9cup\u00e9rer.</p>", "a[href=\"wireless.html#receiver-keyboard-transmission-speed1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Vitesse de transmission du clavier du destinataire<a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#receiver-keyboard-transmission-speed1\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Restaurer les param\u00e8tres par d\u00e9faut<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Lorsqu\u2019une erreur inconnue se produit sur le scanner, vous pouvez r\u00e9initialiser le scanner en restaurant les param\u00e8tres par d\u00e9faut.</p>", "a[href=\"barcode.html#enable-all-symbologies\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Activer toutes les symboles<a class=\"headerlink\" href=\"#enable-all-symbologies\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"scanmode.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de scan<a class=\"headerlink\" href=\"#scan-mode\" title=\"Lien vers cette rubrique\">#</a></h1><h2>D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Param\u00e8tres du syst\u00e8me<a class=\"headerlink\" href=\"#system-settings\" title=\"Lien vers cette rubrique\">#</a></h1><h2>Restaurer les param\u00e8tres par d\u00e9faut<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Lorsqu\u2019une erreur inconnue se produit sur le scanner, vous pouvez r\u00e9initialiser le scanner en restaurant les param\u00e8tres par d\u00e9faut.</p>", "a[href=\"faq.html#question-2-the-scanner-scans-successfully-beeps-twice-and-can-upload-data-normally-what-is-going-on\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Question 2 : Le scanner scanne avec succ\u00e8s, bips deux fois et peut t\u00e9l\u00e9charger des donn\u00e9es normalement. Que se passe-t-il ?<a class=\"headerlink\" href=\"#question-2-the-scanner-scans-successfully-beeps-twice-and-can-upload-data-normally-what-is-going-on\" title=\"Lien vers cette rubrique\">#</a></h2><p><strong>R\u00e9ponse:</strong> La batterie du pistolet du scanner est faible et il invite \u00e0 le recharger.</p>", "a[href=\"scanmode.html#key-trigger-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de d\u00e9clenchement des touches<a class=\"headerlink\" href=\"#key-trigger-mode\" title=\"Lien vers cette rubrique\">#</a></h2><p>Appuyez sur le bouton pour d\u00e9clencher la num\u00e9risation, et rel\u00e2chez le bouton pour terminer la num\u00e9risation. La num\u00e9risation se termine lorsque le scan r\u00e9ussit ou que le temps de lecture d\u00e9passe le temps de lecture unique.</p>", "a[href=\"wired.html#transmission-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de transmission<a class=\"headerlink\" href=\"#transmission-mode\" title=\"Lien vers cette rubrique\">#</a></h2><h3>C\u00e2ble USB comme Clavier<a class=\"headerlink\" href=\"#usb-cable-as-keyboard\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"keyboard.html#keyboard-language\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Langue du clavier<a class=\"headerlink\" href=\"#keyboard-language\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Obtenir la langue actuelle du clavier<a class=\"headerlink\" href=\"#get-current-keyboard-language\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"scanmode.html#auto-sensing-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de d\u00e9tection automatique<a class=\"headerlink\" href=\"#auto-sensing-mode\" title=\"Lien vers cette rubrique\">#</a></h2><p>Dans le mode de d\u00e9tection automatique, le scanner d\u00e9tecte la luminosit\u00e9 de l\u2019environnement environnant. Lorsque la luminosit\u00e9 change, le scan est d\u00e9clench\u00e9. Le scan se termine lorsque le scan est r\u00e9ussi ou que le temps de scan d\u00e9passe le temps de travail unique. Peu importe si le dernier scan a \u00e9t\u00e9 r\u00e9ussi ou a \u00e9chou\u00e9, la luminosit\u00e9 de l\u2019environnement environnant sera \u00e0 nouveau d\u00e9tect\u00e9e.</p>", "a[href=\"barcode.html#end-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Fin de la configuration<a class=\"headerlink\" href=\"#end-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"barcode.html#start-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"process.html#output-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Format de sortie<a class=\"headerlink\" href=\"#output-format\" title=\"Lien vers cette rubrique\">#</a></h2><p>Pour modifier le Format de Transmission de Donn\u00e9es de Scannage, scannez l\u2019un des huit codes \u00e0 barres correspondant au format souhait\u00e9.</p>", "a[href=\"wireless.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode sans fil<a class=\"headerlink\" href=\"#wireless-mode\" title=\"Lien vers cette rubrique\">#</a></h1><p>Ce mode utilise le 2. Bande de fr\u00e9quence GHz pour la transmission de donn\u00e9es et repose sur la technologie de fr\u00e9quence radio (RF) qui se connecte \u00e0 l\u2019ordinateur via un r\u00e9cepteur USB et permet au scanner de se d\u00e9placer librement \u00e0 une certaine distance.</p>", "a[href=\"system.html#get-firmware-version\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obtenir la version du Firmware<a class=\"headerlink\" href=\"#get-firmware-version\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"character.html#end-character-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Param\u00e8tres de caract\u00e8re de fin<a class=\"headerlink\" href=\"#end-character-settings\" title=\"Lien vers cette rubrique\">#</a></h2><p>Le caract\u00e8re de fin est ajout\u00e9 apr\u00e8s le d\u00e9codage des donn\u00e9es au format des donn\u00e9es d\u00e9cod\u00e9es + caract\u00e8re de fin.</p>", "a[href=\"#gy-60u-wireless-scanner-quick-setup-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Guide d\u2019installation rapide du scanner sans fil <strong>GY-60U</strong><a class=\"headerlink\" href=\"#gy-60u-wireless-scanner-quick-setup-guide\" title=\"Lien vers cette rubrique\">#</a></h1>", "a[href=\"character.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Terminateur<a class=\"headerlink\" href=\"#terminator\" title=\"Lien vers cette rubrique\">#</a></h1><h2>D\u00e9marrer la configuration<a class=\"headerlink\" href=\"#start-setup\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"working.html#normal-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode Normal<a class=\"headerlink\" href=\"#normal-mode\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wired.html#usb-hid-multi-key-send-set\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Ensemble d\u2019envoi de cl\u00e9s multiples HID USB<a class=\"headerlink\" href=\"#usb-hid-multi-key-send-set\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#low-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Faible vitesse<a class=\"headerlink\" href=\"#low-speed\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"bluetooth.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Mode Bluetooth<a class=\"headerlink\" href=\"#bluetooth-mode\" title=\"Lien vers cette rubrique\">#</a></h1>", "a[href=\"working.html#storage-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mode de stockage<a class=\"headerlink\" href=\"#storage-mode\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Envoi de donn\u00e9es<a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#data-upload1\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"barcode.html#only-enable-2d-symbologies\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Activer uniquement les symboles 2D<a class=\"headerlink\" href=\"#only-enable-2d-symbologies\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"wireless.html#one-to-one-pairing\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Appairage unique<a class=\"headerlink\" href=\"#one-to-one-pairing\" title=\"Lien vers cette rubrique\">#</a></h2>", "a[href=\"barcode.html#block-barcodes-with-urls\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Bloquer les codes-barres avec des URL<a class=\"headerlink\" href=\"#block-barcodes-with-urls\" title=\"Lien vers cette rubrique\">#</a></h2><p>Bloquer la num\u00e9risation des codes QR URL commen\u00e7ant par <code class=\"docutils literal notranslate\"><span class=\"pre\">http://</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">https://</span></code></p>", "a[href=\"wired.html#usb-keyboard-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Vitesse du clavier USB<a class=\"headerlink\" href=\"#usb-keyboard-speed\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Obtenir la vitesse du clavier<a class=\"headerlink\" href=\"#get-keyboard-speed\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"system.html#sleep-time\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Temps de sommeil<a class=\"headerlink\" href=\"#sleep-time\" title=\"Lien vers cette rubrique\">#</a></h2><p>En scannant le code de r\u00e9glage suivant, vous pouvez r\u00e9gler le scanner pour qu\u2019il passe en mode veille apr\u00e8s une certaine p\u00e9riode de temps o\u00f9 aucun code n\u2019est scann\u00e9, afin de r\u00e9duire la consommation d\u2019\u00e9nergie.</p>", "a[href=\"keyboard.html#case-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">R\u00e9glages du cas<a class=\"headerlink\" href=\"#case-settings\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Normale<a class=\"headerlink\" href=\"#normal\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"process.html#hide-set\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Cacher le jeu<a class=\"headerlink\" href=\"#hide-set\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Cacher les caract\u00e8res de d\u00e9part du code-barres<a class=\"headerlink\" href=\"#hide-barcode-start-chars\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"process.html#appendix\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Annexe<a class=\"headerlink\" href=\"#appendix\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Codes \u00e0 barres num\u00e9riques<a class=\"headerlink\" href=\"#numeric-bar-codes\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"process.html#quick-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configuration rapide<a class=\"headerlink\" href=\"#quick-setup\" title=\"Lien vers cette rubrique\">#</a></h2><h3>Ajouter un pr\u00e9fixe<a class=\"headerlink\" href=\"#id3\" title=\"Lien vers cette rubrique\">#</a></h3>", "a[href=\"wireless.html#high-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Haute Vitesse<a class=\"headerlink\" href=\"#high-speed\" title=\"Lien vers cette rubrique\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
